import{_ as t,o as a,c as s,ag as i}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Web upload","description":"Drop a file in your browser. No install, no wallet.","frontmatter":{"description":"Drop a file in your browser. No install, no wallet."},"headers":[],"relativePath":"getting-started/web-upload.md","filePath":"getting-started/web-upload.md","lastUpdated":1777130260000}'),r={name:"getting-started/web-upload.md"};function o(l,e,n,d,p,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="web-upload" tabindex="-1">Web upload <a class="header-anchor" href="#web-upload" aria-label="Permalink to &quot;Web upload&quot;">​</a></h1><p>The fastest way to try Prova. Open the upload page, drag a file in, get a <code>piece-cid</code> back.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p><strong>Free tier:</strong> 100 MB per file, 200 MB per IP per 24 hours. We sponsor the storage cost. For larger files, sign up for a free token (1 GiB/day) or bring a wallet.</p></div><h2 id="try-it" tabindex="-1">Try it <a class="header-anchor" href="#try-it" aria-label="Permalink to &quot;Try it&quot;">​</a></h2><ol><li>Go to <a href="https://prova.network/upload/" target="_blank" rel="noreferrer">prova.network/upload</a></li><li>Drag a file into the drop zone (or click <em>browse</em>).</li><li>Watch the pipeline run: <ul><li><strong>Compute piece-cid</strong> — your browser hashes the file. The cid is content-addressed; identical files always produce identical cids.</li><li><strong>Stage bytes for the prover</strong> — the worker streams your bytes to a Prova prover.</li><li><strong>Propose deal on Base</strong> — a storage deal is created on-chain.</li><li><strong>Prover accepts and verifies</strong> — the prover fetches, recomputes the cid, posts the first proof.</li><li><strong>Active</strong> — the deal is live. The prover will continue posting a proof every 30 seconds.</li></ul></li><li>You get back: <ul><li>a <strong>piece-cid</strong> like <code>bafy…q4kr</code></li><li>a <strong>deal-id</strong> like <code>d-0x9c4f</code></li><li>a <strong>retrieval URL</strong> like <code>https://prova.network/p/bafy…q4kr</code></li></ul></li></ol><p>The retrieval URL is permanent for the term of the deal (default 30 days on the free tier). You can share it, embed it, point your ENS contenthash at it.</p><h2 id="what-happens-behind-the-scenes" tabindex="-1">What happens behind the scenes <a class="header-anchor" href="#what-happens-behind-the-scenes" aria-label="Permalink to &quot;What happens behind the scenes&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Browser -- &quot;drop file&quot; --&gt; Browser</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Browser -- &quot;POST /api/upload&quot; --&gt; Worker</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Worker -- &quot;PUT bytes&quot; --&gt; Prover</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Worker -- &quot;proposeDeal()&quot; --&gt; Base</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Base -- &quot;DealProposed event&quot; --&gt; Prover</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Prover -- &quot;verify cid + accept&quot; --&gt; Base</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Base -- &quot;deal-id + retrieval URL&quot; --&gt; Browser</span></span></code></pre></div><p>Your file lives on the prover&#39;s disk, addressed by its <code>piece-cid</code>. The prover signs daily proofs. If a proof is missed, the prover is slashed and the file is re-pinned to a healthy prover automatically.</p><h2 id="when-to-step-up" tabindex="-1">When to step up <a class="header-anchor" href="#when-to-step-up" aria-label="Permalink to &quot;When to step up&quot;">​</a></h2><ul><li><strong>Files &gt; 100 MB</strong> — <a href="https://prova.network/app/" target="_blank" rel="noreferrer">sign up</a> for a free token (1 GiB/day quota) or <a href="./cli">use the CLI</a>.</li><li><strong>Long-term storage (&gt; 30 days)</strong> — bring a Base wallet. Pay in USDC, choose a custom term.</li><li><strong>Programmatic uploads</strong> — <a href="./../api/upload">use the API</a> or <a href="./cli">the CLI</a> instead of the browser.</li></ul><h2 id="limits-and-caveats" tabindex="-1">Limits and caveats <a class="header-anchor" href="#limits-and-caveats" aria-label="Permalink to &quot;Limits and caveats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Limit</th><th>Sponsored (no wallet)</th><th>Free token (email)</th><th>Wallet (paid)</th></tr></thead><tbody><tr><td>File size</td><td>100 MB</td><td>5 GiB</td><td>unlimited (gas-bounded)</td></tr><tr><td>Daily quota</td><td>200 MB / IP</td><td>1 GiB / day</td><td>quota = your USDC balance</td></tr><tr><td>Retention</td><td>30 days</td><td>30 days</td><td>up to 5 years</td></tr><tr><td>Slash protection</td><td>yes</td><td>yes</td><td>yes</td></tr></tbody></table><p>The web upload is rate-limited per IP. If you hit the cap, the page tells you. Sign up with an email to lift it.</p>`,14)])])}const g=t(r,[["render",o]]);export{u as __pageData,g as default};
